class Solution:
    def findColumnWidth(self, grid):
        def digit_len(x):
            if x == 0:
                return 1
            neg = x < 0
            x = abs(x)
            count = 0
            while x > 0:
                count += 1
                x //= 10
            return count + (1 if neg else 0)
        rows, cols = len(grid), len(grid[0])
        widths = [0] * cols
        for c in range(cols):
            best = 0
            for r in range(rows):
                d = digit_len(grid[r][c])
                if d > best:
                    best = d
            widths[c] = best
        return widths

