class Solution:
    def findColumnWidth(self, grid):
        rows, cols = len(grid), len(grid[0])
        widths = [0] * cols
        for r in range(rows):
            for c in range(cols):
                l = len(str(grid[r][c]))
                if l > widths[c]:
                    widths[c] = l
        return widths

